package com.careeros.search.application;import com.careeros.search.domain.*;import com.careeros.job.domain.*;import com.careeros.common.exception.ResourceNotFoundException;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service @Transactional public class SavedSearchService{private final SavedSearchRepository r;private final JobPostingRepository jobs;public SavedSearchService(SavedSearchRepository r,JobPostingRepository j){this.r=r;jobs=j;}public SavedSearch save(UUID id,Command c){SavedSearch s=id==null?SavedSearch.create(c.name,c.title,c.sorting,c.minimumScore,c.remote,c.companies,c.locations,c.technologies):get(id);if(id!=null)s.change(c.name,c.title,c.sorting,c.minimumScore,c.remote,c.companies,c.locations,c.technologies);return r.save(s);}public SavedSearch get(UUID id){return r.findById(id).orElseThrow(()->ResourceNotFoundException.forId("SavedSearch",id));}public Page<SavedSearch>list(Pageable p){return r.findAll(p);}public Page<JobPosting>execute(UUID id,Pageable p){var s=get(id);return jobs.findAll(new JobPostingFilter(s.getCompanies().size()==1?s.getCompanies().getFirst():null,s.getTitle(),s.getLocations().size()==1?s.getLocations().getFirst():null,null,s.getRemote(),null),p);}public void delete(UUID id){get(id);r.deleteById(id);}public record Command(String name,String title,String sorting,Integer minimumScore,Boolean remote,List<UUID>companies,List<String>locations,List<String>technologies){}}
